mapper.select:
SELECT c.* FROM case_info c
WHERE c.is_deleted = 0

    AND (c.case_name LIKE CONCAT('%', #{q.keyword}, '%')
      OR c.case_no   LIKE CONCAT('%', #{q.keyword}, '%'))


    AND c.case_category = #{q.caseCategory}


    AND c.case_type = #{q.caseType}


    AND c.status = #{q.status}


    AND c.severity_level = #{q.severityLevel}


    AND c.lead_officer_id = #{q.leadOfficerId}


    AND c.dept_id = #{q.deptId}


    AND c.file_date >= #{q.startDate}


    AND c.file_date <= #{q.endDate}

ORDER BY c.severity_level DESC, c.created_at DESC
